AND ( email ILIKE '%' || #{keyword} || '%' OR nickname ILIKE '%' || #{keyword} || '%' OR real_name ILIKE '%' || #{keyword} || '%' )
AND role = #{role}
AND status = #{status}
AND creator_verified = #{creatorVerified}
ORDER BY created_datetime DESC LIMIT #{size} OFFSET (#{page} - 1) * #{size}

